import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Careers = () => {
  const [jobs, setJobs] = useState([]);
  const [selectedJob, setSelectedJob] = useState(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [formData, setFormData] = useState({ name: '', email: '', resume: null });

  // 1. Backend se Jobs fetch karna
  useEffect(() => {
    const fetchJobs = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/jobs');
        setJobs(res.data);
      } catch (err) {
        console.error("Backend connection failed, using fallback data", err);
        // Fallback data agar server down ho
        setJobs([
          { _id: '1', title: '45 MN Press Crane Operator', loc: 'Saudi Arabia', type: 'On-site', salary: 'SAR 3,500 - 4,000' },
          { _id: '2', title: 'AI Developer (GenAI / LLM)', loc: 'USA', type: 'Hybrid', salary: 'Competitive' }
        ]);
      }
    };
    fetchJobs();
  }, []);

  // 2. Application Submit handle karna
  const handleApply = async (e) => {
    e.preventDefault();
    const data = new FormData();
    data.append('name', formData.name);
    data.append('email', formData.email);
    data.append('jobId', selectedJob._id);
    data.append('resume', formData.resume);

    try {
      await axios.post('http://localhost:5000/api/apply', data);
      alert("Application Sent Successfully!");
      setIsFormOpen(false);
    } catch (err) {
      alert("Error sending application");
    }
  };

  return (
    <div className="bg-white font-sans selection:bg-orange-500 selection:text-white">

      {/* HEADER SECTION */}
      <section className="pt-40 pb-24 px-6 md:px-16 w-full bg-[#0A0A0A] relative overflow-hidden">
        <div className="absolute top-0 right-0 w-96 h-96 bg-orange-600/10 rounded-full blur-[120px]"></div>
        <div className="max-w-7xl mx-auto relative z-10">
          <h1 className="text-6xl md:text-9xl font-black text-white tracking-tighter leading-none mb-8">
            WORK WITH <br /> <span className="text-orange-600 italic font-light">HUDSON.</span>
          </h1>
          <p className="text-gray-400 text-xl max-w-2xl font-medium leading-relaxed">
            Join a global network of technical experts and craft your career in top-tier industries.
          </p>
        </div>
      </section>

      {/* JOBS BOARD */}
      <section className="py-24 px-6 max-w-7xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-end justify-between mb-16 gap-8">
          <div>
            <h2 className="text-5xl font-black text-gray-950 tracking-tighter">Open Positions</h2>
            <p className="text-gray-500 font-bold uppercase text-xs tracking-[0.3em] mt-2">Find your next role</p>
          </div>
          <div className="flex bg-gray-50 p-2 rounded-2xl border border-gray-100">
            <input type="text" placeholder="Search skills..." className="bg-transparent px-4 py-2 outline-none font-medium" />
            <button className="bg-gray-950 text-white px-6 py-2 rounded-xl font-bold">Search</button>
          </div>
        </div>

        <div className="grid gap-6">
          {jobs.map((job) => (
            <div key={job._id} className="group flex flex-col md:flex-row md:items-center justify-between p-10 bg-white border border-gray-100 rounded-[2.5rem] hover:shadow-2xl hover:border-orange-200 transition-all">
              <div className="flex-1">
                <span className="inline-block px-3 py-1 bg-orange-50 text-orange-600 rounded-full text-[10px] font-black uppercase tracking-widest mb-4">
                  {job.type}
                </span>
                <h3 className="text-3xl font-black text-gray-950 mb-2 group-hover:text-orange-600 transition-colors">{job.title}</h3>
                <p className="text-gray-500 font-bold uppercase text-[10px] tracking-widest">{job.loc} • {job.salary}</p>
              </div>
              <div className="mt-8 md:mt-0">
                <button 
                  onClick={() => { setSelectedJob(job); setIsFormOpen(true); }}
                  className="w-full md:w-auto bg-gray-950 text-white px-12 py-4 rounded-2xl font-black hover:bg-orange-600 hover:scale-105 transition-all shadow-xl shadow-gray-200"
                >
                  Apply Now
                </button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* MODAL / SLIDE-OVER FORM */}
      {isFormOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-12 relative">
            <button onClick={() => setIsFormOpen(false)} className="absolute top-8 right-8 text-2xl font-light">✕</button>
            <h2 className="text-4xl font-black tracking-tighter mb-2">Apply for</h2>
            <p className="text-orange-600 font-bold mb-10">{selectedJob?.title}</p>

            <form onSubmit={handleApply} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-gray-400">Full Name</label>
                <input required type="text" className="w-full p-4 bg-gray-50 rounded-xl border-none focus:ring-2 focus:ring-orange-500" onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-gray-400">Email Address</label>
                <input required type="email" className="w-full p-4 bg-gray-50 rounded-xl border-none focus:ring-2 focus:ring-orange-500" onChange={e => setFormData({...formData, email: e.target.value})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-gray-400">Upload CV (PDF)</label>
                <input required type="file" className="w-full p-4 bg-gray-50 rounded-xl border-none file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-black file:bg-orange-100 file:text-orange-700 hover:file:bg-orange-200" onChange={e => setFormData({...formData, resume: e.target.files[0]})} />
              </div>
              <button type="submit" className="w-full bg-orange-600 text-white py-5 rounded-2xl font-black text-lg shadow-2xl shadow-orange-200">Submit Application</button>
            </form>
          </div>
        </div>
      )}

      {/* TESTIMONIALS (Condensed) */}
      <section className="py-24 bg-gray-50">
        <div className="max-w-7xl mx-auto px-6 text-center">
          <h2 className="text-4xl font-black tracking-tighter mb-12">Success Stories</h2>
          <div className="grid md:grid-cols-3 gap-8">
            {testimonials.map((t, i) => (
              <div key={i} className="bg-white p-8 rounded-[2.5rem] text-left border border-gray-100">
                <p className="text-gray-500 italic mb-6">"{t.text}"</p>
                <p className="font-black text-gray-950">{t.name}</p>
                <p className="text-[10px] font-bold text-orange-600 uppercase tracking-widest">{t.role}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

    </div>
  );
};

export default Careers;
